## 4. Application Layer Orchestration

### 4.1 Modifications to `CatalogService`

The `CatalogService` in `sprintcart-pro-application` should implement the `UpdateStockUseCase` interface to handle inbound stock updates from the WMS.

**Location:** `sprintcart-pro-application/src/main/java/com/sprintcart/application/service/CatalogService.java`

**Required Changes:**

```java
package com.sprintcart.application.service;

// ... existing imports ...
import com.sprintcart.domain.ports.in.inventory.UpdateStockUseCase;

/**
 * Application service that orchestrates catalog-related use-cases.
 * Now also implements UpdateStockUseCase for WMS stock updates.
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class CatalogService implements UpdateStockUseCase {

    private final CatalogPort catalogPort;
    private final AdvertisementPort advertisementPort;
    private final EventPublisher eventPublisher;
    private final Validator validator;
    private final Clock clock;

    // ... existing methods ...

    /* ========================================================================
     * UpdateStockUseCase Implementation (for WMS integration)
     * ======================================================================== */

    @Override
    @Transactional
    public StockUpdateResult updateStock(UpdateStockCommand command) throws InvalidStockUpdateException {
        log.info("Processing batch stock update. Correlation: {}, Adjustments: {}",
                command.correlationId(), command.adjustments().size());

        // Check for duplicate processing (idempotency)
        if (isAlreadyProcessed(command.correlationId())) {
            log.info("Duplicate stock update ignored. Correlation: {}", command.correlationId());
            return getPreviousResult(command.correlationId());
        }

        List<SkuUpdateStatus> results = new ArrayList<>();
        int successCount = 0;

        for (StockAdjustment adjustment : command.adjustments()) {
            try {
                updateProductStock(adjustment);
                results.add(new SkuUpdateStatus(adjustment.sku(), true, null, adjustment.newQuantity()));
                successCount++;

                // Check for low stock and trigger automations
                checkLowStockThreshold(adjustment.sku(), adjustment.newQuantity());

            } catch (Exception e) {
                log.warn("Failed to update stock for SKU {}. Error: {}", adjustment.sku(), e.getMessage());
                results.add(new SkuUpdateStatus(adjustment.sku(), false, e.getMessage(), -1));
            }
        }

        StockUpdateResult result = new StockUpdateResult(
                command.correlationId(),
                command.adjustments().size(),
                successCount,
                command.adjustments().size() - successCount,
                results,
                Instant.now(clock)
        );

        // Store result for idempotency checks
        storeProcessedResult(command.correlationId(), result);

        log.info("Batch stock update completed. Success: {}, Failures: {}",
                result.successCount(), result.failureCount());

        return result;
    }

    @Override
    @Transactional
    public SingleSkuUpdateResult updateSingleSku(SingleSkuUpdateCommand command)
            throws InvalidStockUpdateException {
        log.info("Processing single SKU stock update. SKU: {}, New Qty: {}",
                command.sku(), command.newQuantity());

        try {
            StockAdjustment adjustment = new StockAdjustment(
                    command.sku(),
                    -1, // Previous quantity unknown for single update
                    command.newQuantity(),
                    command.warehouseLocation(),
                    command.reason()
            );

            updateProductStock(adjustment);
            checkLowStockThreshold(command.sku(), command.newQuantity());

            return new SingleSkuUpdateResult(
                    command.correlationId(),
                    command.sku(),
                    true,
                    "Stock updated successfully",
                    command.newQuantity(),
                    Instant.now(clock)
            );

        } catch (Exception e) {
            throw new InvalidStockUpdateException("Failed to update SKU " + command.sku() + ": " + e.getMessage(), e);
        }
    }

    private void updateProductStock(StockAdjustment adjustment) {
        // Use existing CatalogPort to update product inventory
        catalogPort.updateStockBySku(adjustment.sku(), adjustment.newQuantity(), adjustment.warehouseLocation());
    }

    private void checkLowStockThreshold(String sku, int newQuantity) {
        // Emit LowStockEvent if below threshold (existing logic)
        catalogPort.findBySku(sku).ifPresent(product -> {
            product.getInventory().ifPresent(inventory -> {
                if (newQuantity < inventory.reorderThreshold()) {
                    log.info("Low stock detected for SKU {}. Qty: {}, Threshold: {}",
                            sku, newQuantity, inventory.reorderThreshold());
                    advertisementPort.pauseCampaignsForProduct(product.getId());
                    eventPublisher.publishAsync(new LowStockEvent(
                            product.getId(), newQuantity, inventory.reorderThreshold(), Instant.now(clock)));
                }
            });
        });
    }

    // Idempotency helpers (would use Redis/database in production)
    private boolean isAlreadyProcessed(String correlationId) {
        // Implementation would check persistent store
        return false;
    }

    private StockUpdateResult getPreviousResult(String correlationId) {
        // Implementation would retrieve from persistent store
        return null;
    }

    private void storeProcessedResult(String correlationId, StockUpdateResult result) {
        // Implementation would persist for idempotency
    }
}
