    38→@Slf4j
    39→@Service
    40→@RequiredArgsConstructor
    41→public class OrderService {
    42→
    43→    private final OrderCommandPort orderCommandPort;
    44→    private final OrderQueryPort orderQueryPort;
    45→    private final PaymentGatewayPort paymentGatewayPort;
    46→    private final InventoryPort inventoryPort;
    47→    private final NotificationPort notificationPort;
    48→    private final DomainMetricsPort metricsPort;
