    58→     * @throws UpstreamFailure     if the payment gateway is unreachable
    59→     */
    60→    @Transactional
    61→    public Order placeOrder(final CheckoutCommand command, final UserId customerId) {
    62→        Instant startedAt = Instant.now(clock);
    63→
    64→        // 1.  Validate & reserve stock in a best-effort manner
    65→        List<OrderItem> requestedItems = command.toOrderItems();
    66→        if (!inventoryPort.reserveStock(requestedItems)) {
    67→            log.warn("Stock reservation failed for customer={}", customerId);
    68→            throw new BusinessViolation("One or more items are out of stock");
    69→        }
    70→
    71→        // 2.  Build domain aggregate
    72→        Order order = Order.placeNew(OrderId.random(), customerId, requestedItems, clock);
    73→        orderCommandPort.save(order);
    74→
    75→        try {
    76→            // 3.  Capture payment
    77→            paymentGatewayPort.charge(order.getId(), command.getPaymentMethod(), order.getGrandTotal());
    78→
    79→            // 4.  Domain state transition
    80→            order.markAsPaid(clock);
    81→            orderCommandPort.save(order);
    82→
    83→            // 5.  Notify customer & update metrics
    84→            notificationPort.orderConfirmation(order);
    85→            metricsPort.incrementCounter("order.placed.ok");
    86→
    87→            return order;
    88→        } catch (PaymentGatewayPort.CardDeclined e) {
    89→            // business failure, rollback transaction
    90→            log.info("Payment declined for order={}, reason={}", order.getId(), e.getMessage());
    91→            throw new BusinessViolation("Payment was declined: " + e.getMessage());
    92→        } catch (PaymentGatewayPort.CommunicationFailure e) {
    93→            // upstream system down; let the job-queue reconcile later
    94→            log.error("Payment gateway unreachable, scheduling retry for order={}", order.getId(), e);
    95→            metricsPort.incrementCounter("order.placed.pending-payment");
    96→            throw new UpstreamFailure("Could not reach payment provider");
    97→        }
    98→        //  Transactional boundary will roll back upon exceptions
    99→    }
   100→
   101→    /**
   102→     * Cancels an existing order.  Refunds the payment and releases reserved stock.
   103→     *
   104→     * @param orderId   the order to cancel
   105→     * @param requestedBy operator performing the action
   106→     */
   107→    @Transactional
   108→    public void cancelOrder(final UUID orderId, final UserId requestedBy) {
   109→        Order order = orderQueryPort.findById(OrderId.of(orderId))
   110→                .orElseThrow(() -> new ResourceNotFound("Order not found: " + orderId));
   111→
   112→        if (!order.canBeCancelled()) {
   113→            throw new BusinessViolation("Order " + orderId + " cannot be cancelled in state " + order.getStatus());
   114→        }
   115→
   116→        if (order.getStatus() == OrderStatus.PAID) {
   117→            paymentGatewayPort.refund(order.getId(), order.getGrandTotal());
   118→        }
   119→
   120→        inventoryPort.releaseStock(order.getItems());
   121→        order.cancel(requestedBy, clock);
   122→
   123→        orderCommandPort.save(order);
   124→
   125→        notificationPort.orderCancelled(order);
   126→        metricsPort.incrementCounter("order.cancelled");
   127→        log.info("Order {} cancelled by user {}", orderId, requestedBy);
   128→    }
   129→
   130→    /**
   131→     * Web-hook entry-point used by the payment provider to acknowledge that an
   132→     * asynchronous payment has settled.
   133→     */
   134→    @Transactional
   135→    public void markOrderAsPaid(final UUID orderId, final String externalTransactionId) {
   136→        Order order = orderQueryPort.findById(OrderId.of(orderId))
   137→                .orElseThrow(() -> new ResourceNotFound("Order not found: " + orderId));
