   139→        if (order.getStatus() == OrderStatus.PAID) {
   140→            log.debug("Ignoring duplicate payment event for order={}", orderId);
   141→            return;
   142→        }
   143→
   144→        order.markAsPaid(clock, externalTransactionId);
   145→        orderCommandPort.save(order);
   146→
   147→        inventoryPort.commitReservedStock(order.getItems());
   148→        notificationPort.orderConfirmation(order);
   149→        metricsPort.incrementCounter("order.paid");
   150→        log.info("Order {} marked as PAID via transaction {}", orderId, externalTransactionId);
   151→    }
   152→
   153→    /**
   154→     * Returns an immutable snapshot DTO of the order.  This keeps domain aggregates
   155→     * from "leaking" into remote layers.
   156→     */
   157→    @Transactional(readOnly = true)
   158→    public OrderDto getOrderDetails(final UUID orderId, final UserId requester) {
