    29→/**
    30→ * DomainEventProcessor is the single entry-point in the application layer that
    31→ * receives <em>domain events</em> emitted by aggregate roots and dispatches them
    32→ * to subscribed handlers.
    33→ * <p>
    34→ * Features:
    35→ * <ul>
    36→ *     <li><b>Dynamic subscription</b> – every Spring bean that implements
    37→ *     {@link DomainEventSubscriber} will be autodetected.</li>
    38→ *     <li><b>At-least-once processing</b> – a lightweight <i>outbox</i> journal
    39→ *     prevents accidental double handling across JVM restarts.</li>
    40→ *     <li><b>Metrics &amp; tracing</b> – processing duration and error counts
    41→ *     are logged so that Prometheus/OpenTelemetry hooks can be added later
    42→ *     without changing business code.</li>
    43→ * </ul>
    44→ *
    45→ * Hexagonal positioning:
    46→ * This class belongs to the <i>application service layer</i> (inside the hexagon)
    47→ * and collaborates with domain and infrastructure layers only through
    48→ * abstractions – no framework classes leak into the domain!
    49→ */
    50→@Slf4j
    51→@Service
    52→@RequiredArgsConstructor
    53→public class DomainEventProcessor implements
    54→        ApplicationListener<DomainEventProcessor.SpringDomainEvent>,
    55→        InitializingBean {
    56→
    57→    /**
    58→     * Light-weight journal that stores the <em>natural key</em> (event id) of
    59→     * every processed message. A production system would back this with a
    60→     * database table; here we keep things in memory to stay self-contained.
    61→     */
    62→    private final Map<UUID, Boolean> processedEventJournal = new ConcurrentHashMap<>();
    63→
    64→    /**
    65→     * Collection of all discovered subscribers. Spring will inject every bean
    66→     * that implements {@link DomainEventSubscriber}.
    67→     */
    68→    private final Collection<DomainEventSubscriber<? extends DomainEvent>> subscribers;
    69→
    70→    /**
    71→     * Async executor configured in {@code AsyncConfiguration}. Must be tuned
    72→     * according to traffic; defaults to CPU*2 thread-pool in Spring Boot.
    73→     */
    74→    private final AsyncTaskExecutor taskExecutor;
    75→
    76→    private final Clock clock = Clock.systemUTC();
    77→
    78→    @Override
    79→    public void afterPropertiesSet() {
    80→        log.info("DomainEventProcessor initialized with {} subscriber(s)",
    81→                subscribers.size());
    82→        subscribers.forEach(s ->
    83→                log.debug("   ↳ {}", s.getClass().getName()));
    84→    }
