    86→    /**
    87→     * Handles events published via {@code ApplicationEventPublisher}. The event
    88→     * is unwrapped and forwarded to {@link #process(DomainEvent)}.
    89→     */
    90→    @Override
    91→    @Transactional(noRollbackFor = Throwable.class)
    92→    public void onApplicationEvent(SpringDomainEvent springEvent) {
    93→        process(springEvent.event());
    94→    }
