    96→    /**
    97→     * Dispatches the given domain event to all matching subscribers.
    98→     *
    99→     * @param event domain event, must be non-null
   100→     */
   101→    public <E extends DomainEvent> void process(@NonNull E event) {
   102→        final UUID eventId = event.eventId();
   103→        if (eventId == null) {
   104→            log.warn("Ignoring event without id: {}", event.getClass().getSimpleName());
   105→            return;
   106→        }
   107→
   108→        // At-least-once check – skip already processed events
   109→        if (processedEventJournal.putIfAbsent(eventId, Boolean.TRUE) != null) {
   110→            log.debug("Event {} already handled, skipping", eventId);
   111→            return;
   112→        }
   113→
   114→        log.info("▶ Processing event {} ({})", eventId, event.getClass().getSimpleName());
   115→
   116→        final Instant start = clock.instant();
   117→
   118→        subscribers.stream()
   119→                   .filter(sub -> sub.supports(event.getClass()))
   120→                   .forEach(sub -> dispatchAsync(sub, event));
   121→
   122→        final Duration duration = Duration.between(start, clock.instant());
   123→        log.info("✔ Event {} processed in {} ms", eventId, duration.toMillis());
   124→    }
