   126→    /**
   127→     * Dispatches event handling to background thread. An individual subscriber
   128→     * failure does <strong>not</strong> prevent other subscribers from running.
   129→     */
   130→    private <E extends DomainEvent> void dispatchAsync(
   131→            DomainEventSubscriber<E> subscriber, E event) {
   132→
   133→        CompletableFuture
   134→            .runAsync(() -> invokeHandler(subscriber, event), taskExecutor)
   135→            .exceptionally(ex -> {
   136→                log.error("❌ Subscriber '{}' failed for event {}",
   137→                        subscriber.getClass().getSimpleName(), event.eventId(), ex);
