   143→    /**
   144→     * Invokes subscriber handler with proper error boundaries. Wrapped into its
   145→     * own method to produce cleaner stack traces inside {@link CompletableFuture}.
   146→     */
   147→    private <E extends DomainEvent> void invokeHandler(
   148→            DomainEventSubscriber<E> subscriber, E event) {
   149→
   150→        try {
   151→            subscriber.handle(event);
   152→            log.debug("↳ {} handled by {}", event.getClass().getSimpleName(),
   153→                    subscriber.getClass().getSimpleName());
   154→        } catch (DataAccessException dae) {
   155→            // Non-transient DB error – rethrow to trigger retry/back-off
   156→            throw dae;
   157→        } catch (Exception e) {
   158→            // Shield rest of the pipeline; mark failure for DLQ
   159→            log.error("Subscriber {} threw exception for event {}",
   160→                    subscriber.getClass().getName(), event.eventId(), e);
   161→            throw e;
   162→        }
   163→    }
