   182→     * Extend this in <code>domain.events.*</code> packages.
   183→     */
   184→    public interface DomainEvent extends Serializable {
   185→        @Serial
   186→        long serialVersionUID = 1L;
   187→
   188→        /**
   189→         * Globally unique identifier that guarantees idempotency.
   190→         */
   191→        @NonNull UUID eventId();
