    29→/**
    30→ * Application-layer service responsible for orchestrating the fulfillment work-flow.
    31→ *
    32→ * The class purposely does not leak any framework-specific constructs (such as
    33→ * DTOs or entities) to the outside world; it only speaks domain objects.
    34→ * <p>
    35→ * Steps performed:
    36→ *  1. Retrieve & validate the Order in a transaction-safe manner.
    37→ *  2. Reserve inventory and record shortages.
    38→ *  3. Generate a picking list and corresponding shipment label.
    39→ *  4. Persist Order state transitions (Fulfilling -> Fulfilled).
    40→ *  5. Emit domain events and user notifications.
    41→ */
    42→@Slf4j
    43→@Service
    44→@RequiredArgsConstructor
    45→public class FulfillmentService {
    46→
    47→    // ————————————————————————————————————————————————————————— Ports & Dependencies
    48→    private final OrderRepository orderRepository;
    49→    private final InventoryGateway inventoryGateway;
    50→    private final ShippingGateway shippingGateway;
    51→    private final NotificationGateway notificationGateway;
    52→    private final DomainEventPublisher eventPublisher;
    53→    private final TimeProvider timeProvider;
    54→
    55→    private static final int MAX_RETRIES_ON_CONTENTION = 3;
    56→
    57→    /**
    58→     * Triggers the full fulfillment workflow for a single order.
    59→     *
    60→     * @param orderId    Business identifier of the order.
    61→     * @param operatorId User who initiated the action (auditing / productivity KPI).
    62→     * @return An immutable value object describing the outcome.
    63→     */
    64→    public FulfillmentResult fulfill(UUID orderId, OperatorId operatorId) {
    65→        Instant startedAt = timeProvider.now();
    66→        AtomicInteger attemptCounter = new AtomicInteger(0);
    67→
    68→        while (attemptCounter.incrementAndGet() <= MAX_RETRIES_ON_CONTENTION) {
    69→            try {
    70→                return fulfillInternal(orderId, operatorId, startedAt);
    71→            } catch (OptimisticLockingFailureException e) {
    72→                log.warn("Contention detected while trying to fulfill order {} (attempt {}/{})",
    73→                        orderId, attemptCounter.get(), MAX_RETRIES_ON_CONTENTION);
    74→                sleepBackOff(attemptCounter.get());
    75→            }
    76→        }
    77→        throw new FulfillmentException("Could not fulfill order " + orderId + " due to repeated concurrent modifications");
    78→    }
    79→
    80→    // ——————————————————————————————————————————————————————————————— Internal
    81→
    82→    @Transactional
    83→    protected FulfillmentResult fulfillInternal(UUID orderId,
    84→                                                OperatorId operatorId,
    85→                                                Instant startedAt) {
    86→
    87→        Order order = orderRepository.findById(orderId)
    88→                .orElseThrow(() -> new FulfillmentException("Order " + orderId + " not found"));
    89→
    90→        if (order.getStatus() != OrderStatus.PAID) {
    91→            throw new BusinessRuleViolationException("Only orders in PAID state can be fulfilled");
    92→        }
    93→
    94→        // 1. Reserve inventory
    95→        InventoryReservationSummary reservationSummary = reserveInventory(order);
    96→
    97→        // 2. Create picking list (domain object for warehouse employees)
    98→        PickingList pickingList = generatePickingList(order, reservationSummary);
    99→
   100→        // 3. Ship (interacts with external carrier API)
   101→        ShipmentLabel shipmentLabel = generateShipmentLabel(order, pickingList);
   102→
   103→        // 4. Transition order state
   104→        order.markAsFulfilled(shipmentLabel.trackingNumber(), timeProvider.now());
   105→        orderRepository.save(order);
   106→
   107→        // 5. Emit domain events & notifications
   108→        eventPublisher.publish(new OrderFulfilledEvent(order.getId(), operatorId, shipmentLabel.trackingNumber()));
   109→        notificationGateway.notifyCustomerFulfilled(order.getCustomerId(), order.getId(), shipmentLabel);
   110→
   111→        Duration totalDuration = Duration.between(startedAt, timeProvider.now());
   112→        log.info("Order {} fulfilled in {} ms", orderId, totalDuration.toMillis());
   113→
   114→        return new FulfillmentResult(orderId,
   115→                                     shipmentLabel.trackingNumber(),
   116→                                     reservationSummary,
   117→                                     totalDuration);
   118→    }
   119→
   120→    // —————————————————————————————————————————————————————————— Sub-Steps
   121→
   122→    private InventoryReservationSummary reserveInventory(Order order) {
   123→        InventoryReservationSummary summary = new InventoryReservationSummary();
   124→
   125→        for (OrderLine line : order.getOrderLines()) {
   126→            StockReservationResult result =
   127→                    inventoryGateway.reserveStock(line.getSku(), line.getQuantity());
   128→
   129→            summary.add(result);
   130→
   131→            if (!result.isSuccessful()) {
   132→                log.warn("Partial stock reservation for order {} – SKU {} only {} reserved out of {}",
   133→                        order.getId(), line.getSku(), result.reserved(), line.getQuantity());
   134→            }
   135→        }
   136→
   137→        if (!summary.isFullyReserved()) {
   138→            throw new InsufficientStockException(order.getId(), summary);
   139→        }
   140→        return summary;
   141→    }
   142→
   143→    private PickingList generatePickingList(Order order, InventoryReservationSummary summary) {
   144→        List<PickingItem> items = order.getOrderLines().stream()
   145→                .map(ol -> new PickingItem(ol.getSku(), ol.getQuantity(), summary.getLocatorFor(ol.getSku())))
   146→                .toList();
   147→
   148→        return new PickingList(order.getId(), items, order.getShippingAddress());
   149→    }
   150→
   151→    private ShipmentLabel generateShipmentLabel(Order order, PickingList pickingList) {
   152→        Address shipTo = order.getShippingAddress();
   153→        return shippingGateway.createShipment(order.getId(), shipTo, pickingList.totalWeight());
   154→    }
