   158→    private void sleepBackOff(int attempt) {
   159→        try {
   160→            Thread.sleep(200L * attempt); // simple linear back-off
   161→        } catch (InterruptedException ie) {
   162→            Thread.currentThread().interrupt();
   163→        }
   164→    }
