   169→     * DTO representing the outcome of the fulfillment process.
   170→     * Could later be extended with analytics metadata.
   171→     */
   172→    public record FulfillmentResult(UUID orderId,
   173→                                    String trackingNumber,
   174→                                    InventoryReservationSummary reservationSummary,
   175→                                    Duration processingTime) {
   176→    }
